using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

builder.Services.AddSingleton<TicketModelTrainer>();

// Train model at startup and register prediction engine pool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ticket_model.zip");
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "tickets.csv");

builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(modelPath: modelPath, watchForChanges: true);

var app = builder.Build();

// Train model before handling requests
var trainer = app.Services.GetRequiredService<TicketModelTrainer>();
var metrics = trainer.TrainAndSaveModel(dataPath, modelPath);
app.Logger.LogInformation("Model trained. Metrics:\n{Metrics}", metrics);

app.MapControllers();
app.Run();

